export const CONDITIONS = RAW.map(c => ({ ...c, slug: slugify(c.name) }));

export function getConditionBySlug(slug) {
  return CONDITIONS.find(c => c.slug === slug);
}

export function getConditionsByCategory(cat) {
  return CONDITIONS.filter(c => c.cat === cat);
}

export function getAllSlugs() {
  return CONDITIONS.map(c => c.slug);
}
